# OData batch: multiples operaciones en un solo HTTP request

boundary = 'batch_001'
changeset = 'changeset_001'

body = f'''--{boundary}
Content-Type: multipart/mixed; boundary={changeset}

--{changeset}
Content-Type: application/http
Content-Transfer-Encoding: binary

POST OpportunityCollection HTTP/1.1
Content-Type: application/json

{{"Name": "Opp 1", "AccountID": "ACC001"}}
--{changeset}
Content-Type: application/http
Content-Transfer-Encoding: binary

POST OpportunityCollection HTTP/1.1
Content-Type: application/json

{{"Name": "Opp 2", "AccountID": "ACC002"}}
--{changeset}--
--{boundary}--'''

r = session.post(BASE + '/$batch',
    data=body,
    headers={
        'Content-Type': f'multipart/mixed; boundary={boundary}',
        'X-CSRF-Token': csrf
    })
print(f'Batch: {r.status_code}')

def create_opportunity_fiori(page, data):
    # 1. Navegar a Opportunities
    page.locator('[class*="sapMTile"]:has-text("Opportunities"), '
                 'a:has-text("Opportunities")').click()
    page.wait_for_selector('[class*="sapMList"]', timeout=10000)

    # 2. Click Create
    page.locator('button:has-text("Create"), button:has-text("+")').click()
    page.wait_for_timeout(1000)

    # 3. Llenar campos
    for label, value in data.items():
        field = page.locator(f'[aria-label="{label}"] input, '
                             f'input[aria-label="{label}"]')
        if field.count() > 0:
            field.first.fill(str(value))
            field.first.press('Tab')
            page.wait_for_timeout(300)

    # 4. Save
    page.locator('button:has-text("Save")').click()
    page.wait_for_timeout(2000)

    # 5. Verificar
    toast = page.locator('[class*="sapMMessageToast"]')
    try:
        toast.wait_for(state='visible', timeout=3000)
        return {'success': True, 'message': toast.text_content()}
    except:
        strip = page.locator('[class*="sapMMessageStrip"]')
        if strip.count() > 0:
            return {'success': 'Error' not in strip.get_attribute('class'),
                    'message': strip.text_content()}
    return {'success': False, 'message': 'No feedback'}

