def create_lead(page, data):
    page.locator('a:has-text("Leads"), [class*="sapMTile"]:has-text("Leads")').click()
    page.wait_for_timeout(1000)
    page.locator('button:has-text("Create"), button:has-text("+")').click()
    page.wait_for_timeout(1000)

    field_map = {
        'Company': data.get('company', ''),
        'Contact': data.get('contact', ''),
        'Source': data.get('source', 'Web'),
        'Notes': data.get('notes', ''),
    }
    for label, value in field_map.items():
        if value:
            f = page.locator(f'[aria-label*="{label}"] input')
            if f.count() > 0:
                f.first.fill(value)
                f.first.press('Tab')
                page.wait_for_timeout(300)

    page.locator('button:has-text("Save")').click()
    page.wait_for_timeout(2000)

def safe_fiori_action(page, action_fn, description=''):
    try:
        return action_fn(page)
    except TimeoutError:
        # Verificar si hay dialog de error
        dialog = page.locator('[class*="sapMDialog"]')
        if dialog.count() > 0 and dialog.is_visible():
            msg = dialog.locator('[class*="sapMText"]').text_content()
            dialog.locator('button:has-text("Close"), button:has-text("OK")').click()
            raise Exception(f'Dialog error: {msg}')
        # Verificar message strip
        strip = page.locator('[class*="sapMMessageStripError"]')
        if strip.count() > 0:
            msg = strip.text_content()
            raise Exception(f'Strip error: {msg}')
        raise
    except Exception as e:
        page.screenshot(path=f'fiori_error_{description}.png')
        raise

